def cond_rank(triple):
    rows = [[coord(k, pt) for k in range(_sage_const_4 )] for pt in triple]
    return matrix(F, rows).rank()

print("u-fiber triples (predict rank 2 => ker jumps to 2 = h^0(N)):", flush=True)
